import type { Car, SearchResponse, CarResponse, EnrichedCar } from "@/types/car";
import carsEnrichedData from "@/backend/data/cars-enriched.json";

const enrichedCars: EnrichedCar[] = carsEnrichedData as EnrichedCar[];

function enrichedToCar(ec: EnrichedCar): Car {
  return {
    Name: ec.brand,
    Model: ec.model,
    Image: ec.image,
    Price: ec.price,
    Location: ec.location,
  };
}

export function getAllCars(): Car[] {
  return enrichedCars.map(enrichedToCar);
}

export function getCarByIndex(index: number): Car | undefined {
  const ec = enrichedCars[index];
  return ec ? enrichedToCar(ec) : undefined;
}

export function findCarsByQuery(query: string): Car[] {
  const lower = query.toLowerCase();
  return enrichedCars
    .filter(
      (car) =>
        car.brand.toLowerCase().includes(lower) ||
        car.model.toLowerCase().includes(lower) ||
        car.location.toLowerCase().includes(lower) ||
        car.fullName.toLowerCase().includes(lower)
    )
    .map(enrichedToCar);
}

export function getAllEnrichedCars(): EnrichedCar[] {
  return enrichedCars;
}

export function getEnrichedCarByIndex(index: number): EnrichedCar | undefined {
  return enrichedCars[index];
}

export async function searchCarsWithAI(
  query: string,
  userLat?: number,
  userLng?: number,
  userState?: string
): Promise<SearchResponse> {
  const res = await fetch("/api/search", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ query, userLat, userLng, userState }),
  });

  if (!res.ok) throw new Error("Search failed");
  return res.json();
}

export async function fetchAllCars(): Promise<CarResponse[]> {
  const res = await fetch("/api/cars");
  if (!res.ok) throw new Error("Failed to fetch cars");
  const data = await res.json();
  return data.cars;
}

export async function fetchCarById(id: string): Promise<CarResponse | null> {
  const res = await fetch(`/api/cars/${id}`);
  if (!res.ok) return null;
  const data = await res.json();
  return data.car;
}

export function carResponseToCar(cr: CarResponse): Car {
  return {
    Name: cr.brand,
    Model: cr.model,
    Image: cr.image,
    Price: cr.price,
    Location: cr.location,
  };
}
