"use client";

import clsx from "clsx";
import { getAllEnrichedCars } from "@/lib/cars";
import { useMemo } from "react";

interface BrandsRowProps {
  selected?: string;
  onSelect?: (brand: string) => void;
}

export function BrandsRow({ selected = "Hyundai", onSelect }: BrandsRowProps) {
  const brands = useMemo(() => {
    const set = new Set<string>();
    for (const car of getAllEnrichedCars()) set.add(car.brand);
    return Array.from(set).sort((a, b) => a.localeCompare(b, "pt-BR"));
  }, []);

  const effectiveSelected = brands.includes(selected) ? selected : brands[0] ?? selected;

  return (
    <section className="flex flex-col gap-6">
      <h2 className="text-lg font-bold text-gray-900 text-center">
        Busque por Marcas
      </h2>
      <div className="flex flex-wrap items-center justify-center gap-6">
        {brands.map((brand) => {
          return (
            <button
              key={brand}
              onClick={() => onSelect?.(brand)}
              className={clsx(
                "group flex flex-col items-center justify-center rounded-full bg-white transition-all",
                "h-[120px] w-[120px] border-2 hover:shadow-md hover:scale-105",
                brand === effectiveSelected
                  ? "border-blue-600 shadow-md scale-105"
                  : "border-gray-200 hover:border-blue-600"
              )}
            >
              <span
                className={clsx(
                  "text-center text-xs font-bold text-gray-900 group-hover:text-blue-600"
                )}
              >
                {brand}
              </span>
            </button>
          );
        })}
      </div>
    </section>
  );
}
